form:Form.form:Scripts:
		var CLASS_TREE=null;
function sendReqAsync(content, callBack) {
    var msg;
    var objDoc;

    if (content == null)
        content = "";

    msg = "<http-envelope service='ProxyEngine' request='send' user-token='" + g_strToken + "'>" + content + "</http-envelope>";

    var hr = getHR();                 
    hr.open("POST", g_location + "ProxyEngine.aspx", true);
    hr.onreadystatechange = function() 
    { 
      //Resultado
      if (hr.readyState == 4) 
      {
        if (hr.status == 200) 
        {
            try 
            {
              objDoc = createDoc(hr.responseText);
            } catch (e) 
            {
              alert("sendReqAsync(): " + e.number + "  " + e.description);
						  enable_buttons();
					    return;
            }

            //Envia el resultado
            if (callBack)
              callBack(objDoc);
        } else 
        {
          alert("sendReqAsync(): ERROR " + hr.status);
				  enable_buttons();
			    return;
        }
      }
    };

    hr.send(msg);
}


function SQLGetAsync(qry, param, callBack) 
{                              
	sendReqAsync("<content-send SrvName=\"xquery\" Request=\"get-sql\" ><qry:declare xmlns:qry=\"nomad_engine.form\">"+param+"</qry:declare>"+qry+"</content-send>", function(doc) { 

    //Switchea las posibles respuestas
    strService  = doc.documentElement.attributes.getNamedItem("service").value;
    strResponse = doc.documentElement.attributes.getNamedItem("response").value;

    switch (strResponse) 
    {
        case "send-response":
          var eleResponse = doc.documentElement.childNodes.item(0);
          objResult = new NomadProxyResponse(eleResponse.attributes.getNamedItem("service").value, eleResponse.attributes.getNamedItem("response").value, eleResponse.childNodes.item(0));

					//Resultado                                       
          //Envia el resultado
          if (callBack)
            callBack(objResult.Message());
			    return;

        default:
          alert("invalid server reply, "+strResponse);
				  enable_buttons();
			    return;
    }
	});
}


function LoadChilds(objTree, objGroup)
{
	var id=objGroup.FullId.split("/"); id=id[id.length-1];

	SQLGetAsync(Ctrl("main").getResource("qry_estructura"), "<PARAM id=\""+id+"\" empresa=\"" + Ctrl("empresa").GetXValue() + "\" />", 
		function(resultTXT) {
			objTree.SetXML(objGroup.FullId, resultTXT);
		}
	);
}

function onClick()
{                                          
	var fullid=Ctrl("oi_estructura_full").GetXValue();


	if (CLASS_TREE.GetGroup(fullid) && fullid!=".") 
	{
		var id=fullid.split("/"); 
		id=id[id.length-1];
		if (id==".") id="";

 		Ctrl("oi_estructura").SetXValue(id);
		CtrlEnabled("ACCEPT",true);
	} else                               
 	{
 		CtrlEnabled("ACCEPT",false);      
 		Ctrl("oi_estructura").SetXValue("");
 	}
}

function onLoad()
{       
  //Valor RAIZ!!!
	Ctrl("oi_estructura_full").SetXValue(".");

 	//XML RAIZ!!!!
	var xmlRoot=Ctrl("main").getResource("xml_root");
	CLASS_TREE=clsClientTree("contESTR","oi_estructura_full","CLOCK.ico","folder-close.ico","folder.ico","item.ico",true,LoadChilds,null,onClick,1000);
	CLASS_TREE.SetXML(null, xmlRoot);
	CLASS_TREE.SetSelectedId(".");
	CLASS_TREE.ClickExpGroup(".");

	//Deshabilito el aceptar 
  CtrlEnabled("ACCEPT",false);      
	Ctrl("oi_estructura").SetXValue("");
}    

function SearchText()
{                   
	if (Ctrl("buscar").GetXValue()!='')
	{                             
		var P=new NomadXML("PARAM");
		P.SetAttr("empresa", Ctrl("empresa").GetXValue());
		P.SetAttr("txt_find", Ctrl("buscar").GetXValue());

		SQLGetAsync(Ctrl("main").getResource("qry_find"), P.ToString(), function(result) {
			var P=new NomadXML(result);
			if (P.GetAttr("mode")!='')
			{     
				SelectTO(P.GetAttr("fullid"));
			}
		});
	}
}            

function SelectTO(fullId)
{
	var parts = fullId.split('/');
	var currId = "";
	var prevGroup = null;

	for(var t=0; t<parts.length; t++)
	{
		if (prevGroup != null && !prevGroup.isLoadChild)
		{
			SQLGetAsync(Ctrl("main").getResource("qry_estructura"), "<PARAM id=\""+parts[t-1]+"\" />", 
				function(resultTXT) 
				{
					CLASS_TREE.SetXML(currId, resultTXT);
					CLASS_TREE.ClickExpGroup(currId);
					SelectTO(fullId);
				}
			);
			return;
		}

		currId+=(currId?"/":"")+parts[t];
		prevGroup = CLASS_TREE.GetGroup(currId);
		if (prevGroup == null) return;
	}

	CLASS_TREE.SetSelectedId(fullId);
}

function ACCEPT()
{       
	if(Ctrl("oi_estructura").GetXValue() == "") return;

	if (Ctrl("subestr").GetXValue() == "1")
	{
			nSQL = GetProxy().SQLService();
			var MyXML = nSQL.GetXML(Ctrl("main").getResource("qry_load"),"<PARAM id=\"" + Ctrl("oi_estructura").GetXValue() + "\"/>");
	  	Ctrl("ids").SetXValue(MyXML.GetAttr("ids"));		
	} else
	{
		Ctrl("ids").SetXValue(Ctrl("oi_estructura").GetXValue())		
	}

	//alert(Ctrl("ids").GetXValue());	
	Ctrl("main").DoEvent("ACCEPT");
}
